        s.push_str(&format!(
            "                UartTx {{ u: self.u, _state: PhantomData }}\n"
        ));
        s.push_str("            }\n");
        s.push_str("        }\n\n");

        s.push_str(&format!("        pub struct UartRx<'a> {{\n"));
