fn is_uart_like(name: &str) -> bool {
    let upper = name.to_ascii_uppercase();
    upper.starts_with("UART") || upper.starts_with("UARTE")
}

fn collect_uarts(device: &svd::Device) -> Vec<UartInfo> {
    let mut out = Vec::new();
    for p in &device.peripherals {
        if !is_uart_like(&p.name) {
            continue;
        }
        let items = peripheral_register_items(device, p);
        if items.is_empty() {
            continue;
        }

        let Some((tasks_startrx_name, _)) = find_register(items, "TASKS_STARTRX") else {
            continue;
        };
        let Some((tasks_stoprx_name, _)) = find_register(items, "TASKS_STOPRX") else {
            continue;
        };
        let Some((tasks_starttx_name, _)) = find_register(items, "TASKS_STARTTX") else {
            continue;
        };
        let Some((tasks_stoptx_name, _)) = find_register(items, "TASKS_STOPTX") else {
            continue;
        };
        let Some((tasks_flushrx_name, _)) = find_register(items, "TASKS_FLUSHRX") else {
            continue;
        };

        let Some((events_rxrdy_name, _)) = find_register(items, "EVENTS_RXDRDY") else {
            continue;
        };
        let Some((events_txrdy_name, _)) = find_register(items, "EVENTS_TXDRDY") else {
            continue;
        };
        let Some((events_endrx_name, _)) = find_register(items, "EVENTS_ENDRX") else {
            continue;
        };
        let Some((events_endtx_name, _)) = find_register(items, "EVENTS_ENDTX") else {
            continue;
        };
        let Some((events_error_name, _)) = find_register(items, "EVENTS_ERROR") else {
            continue;
        };

        let Some((intenset_name, _intenset_reg)) = find_register(items, "INTENSET") else {
            continue;
        };

        let Some((baudrate_name, baudrate_reg)) = find_register(items, "BAUDRATE") else {
            continue;
        };
        let baudrate_field = baudrate_reg
            .field
            .iter()
            .find(|f| f.name.eq_ignore_ascii_case("BAUDRATE"))
            .cloned()
            .or_else(|| baudrate_reg.field.first().cloned());
        let Some(baudrate_field) = baudrate_field else {
            continue;
        };

        let Some((config_name, config_reg)) = find_register(items, "CONFIG") else {
            continue;
        };
        let config_hwfc_field = config_reg
            .field
            .iter()
            .find(|f| f.name.eq_ignore_ascii_case("HWFC"))
            .cloned();
        let config_parity_field = config_reg
            .field
            .iter()
            .find(|f| f.name.eq_ignore_ascii_case("PARITY"))
            .cloned();

        out.push(UartInfo {
            periph_name: p.name.clone(),
            periph_mod: sanitize_module_name(&p.name),
            hal_mod: sanitize_field_name(&p.name),

            field_tasks_startrx: sanitize_field_name(&tasks_startrx_name),
            field_tasks_stoprx: sanitize_field_name(&tasks_stoprx_name),
            field_tasks_starttx: sanitize_field_name(&tasks_starttx_name),
            field_tasks_stoptx: sanitize_field_name(&tasks_stoptx_name),
            field_tasks_flushrx: sanitize_field_name(&tasks_flushrx_name),

            field_events_rxrdy: sanitize_field_name(&events_rxrdy_name),
            field_events_txrdy: sanitize_field_name(&events_txrdy_name),
            field_events_endrx: sanitize_field_name(&events_endrx_name),
            field_events_endtx: sanitize_field_name(&events_endtx_name),
            field_events_error: sanitize_field_name(&events_error_name),

            field_intenset: sanitize_field_name(&intenset_name),

            field_baudrate: sanitize_field_name(&baudrate_name),
            baudrate_field,

            field_config: sanitize_field_name(&config_name),
            config_hwfc_field,
            config_parity_field,
        });
    }
    out
}

fn parse_compare_index(name_upper: &str) -> Option<usize> {
    let p = name_upper.find("COMPARE")?;
    let rest = &name_upper[p + "COMPARE".len()..];
    let digits = rest
        .chars()
        .take_while(|c| c.is_ascii_digit())
        .collect::<String>();
    if digits.is_empty() {
        return None;
    }
    digits.parse::<usize>().ok()
}

fn find_register_prefer_exact<'a>(
    items: &'a [svd::RegisterBlockItem],
    needle: &str,
) -> Option<(String, &'a svd::Register)> {
    let needle_upper = needle.to_ascii_uppercase();
    for it in items {
        match it {
            svd::RegisterBlockItem::Register { register } => {
                if register.name.to_ascii_uppercase() == needle_upper {
                    return Some((register.name.clone(), register));
                }
            }
            svd::RegisterBlockItem::Cluster { cluster } => {
                if let Some(x) = find_register_prefer_exact(cluster.items.as_slice(), needle) {
                    return Some(x);
                }
            }
        }
    }
    find_register(items, needle)
}

fn find_register<'a>(
    items: &'a [svd::RegisterBlockItem],
    needle: &str,
) -> Option<(String, &'a svd::Register)> {
    for it in items {
        match it {
            svd::RegisterBlockItem::Register { register } => {
                if register.name.to_ascii_uppercase().contains(needle) {
                    return Some((register.name.clone(), register));
                }
            }
            svd::RegisterBlockItem::Cluster { cluster } => {
                if let Some(x) = find_register(cluster.items.as_slice(), needle) {
                    return Some(x);
                }
            }
        }
    }
    None
}

fn field_lsb_width(f: &svd::Field) -> (u32, u32) {
    match f.bit_range {
        svd::BitRange::BitRangeString { msb, lsb } => (lsb, msb.saturating_sub(lsb) + 1),
        svd::BitRange::LsbMsb { lsb, msb } => (lsb, msb.saturating_sub(lsb) + 1),
        svd::BitRange::BitOffsetWidth {
            bit_offset,
            bit_width,
        } => (bit_offset, bit_width.unwrap_or(1)),
    }
}

fn parse_enum_u64(s: &str) -> Option<u64> {
    let s = s.trim();
    let s = s.strip_prefix('+').unwrap_or(s);
    if let Some(hex) = s.strip_prefix("0x").or_else(|| s.strip_prefix("0X")) {
        let digits = hex.trim();
        if digits.is_empty() || digits.contains('x') || digits.contains('X') {
            return None;
        }
        u64::from_str_radix(digits, 16).ok()
    } else if let Some(bin) = s.strip_prefix("0b") {
        let digits = bin.trim();
        if digits.is_empty() || digits.contains('x') || digits.contains('X') {
            return None;
        }
        u64::from_str_radix(digits, 2).ok()
    } else if let Some(bin) = s.strip_prefix('#') {
        let digits = bin.trim();
        if digits.is_empty() || digits.contains('x') || digits.contains('X') {
            return None;
        }
        u64::from_str_radix(digits, 2).ok()
    } else if s.chars().all(|c| c.is_ascii_digit()) {
        s.parse::<u64>().ok()
    } else {
        None
    }
}

pub fn sanitize_file_stem(s: &str) -> String {
    let mut out = String::new();
    for ch in s.chars() {
        if ch.is_ascii_alphanumeric() || ch == '_' || ch == '-' {
            out.push(ch);
        } else {
            out.push('_');
        }
    }
    if out.is_empty() {
        "device".to_string()
    } else {
        out
    }
}

fn sanitize_module_name(s: &str) -> String {
    let mut out = String::new();
    for (i, ch) in s.chars().enumerate() {
        let good = ch.is_ascii_alphanumeric() || ch == '_';
        let ch = if good { ch } else { '_' };
        if i == 0 && ch.is_ascii_digit() {
            out.push('_');
        }
        out.push(ch);
    }
    if out.is_empty() {
        "PERIPH".to_string()
    } else if is_rust_keyword(&out.to_ascii_lowercase()) {
        format!("{out}_")
    } else {
        out
    }
}

fn sanitize_field_name(s: &str) -> String {
    let mut out = String::new();
    for (i, ch) in s.chars().enumerate() {
        let good = ch.is_ascii_alphanumeric() || ch == '_';
        let ch = if good { ch } else { '_' };
        if i == 0 && ch.is_ascii_digit() {
            out.push('_');
        }
        out.push(ch.to_ascii_lowercase());
    }
    if out.is_empty() {
        "_field".to_string()
    } else if is_rust_keyword(&out) {
        format!("{out}_")
    } else {
        out
    }
}

fn sanitize_type_name(s: &str) -> String {
    let mut out = String::new();
    let mut upper_next = true;
    for ch in s.chars() {
        if ch.is_ascii_alphanumeric() {
            if out.is_empty() && ch.is_ascii_digit() {
                out.push('_');
            }
            if upper_next {
                out.push(ch.to_ascii_uppercase());
                upper_next = false;
            } else {
                out.push(ch.to_ascii_lowercase());
            }
        } else {
            upper_next = true;
        }
    }
    if out.is_empty() {
        "Type".to_string()
    } else if is_rust_keyword(&out.to_ascii_lowercase()) {
        format!("{out}_")
    } else {
        out
    }
}

fn sanitize_variant_name(s: &str) -> String {
    let mut out = String::new();
    let mut upper_next = true;
    for ch in s.chars() {
        if ch.is_ascii_alphanumeric() {
            if out.is_empty() && ch.is_ascii_digit() {
                out.push('_');
            }
            if upper_next {
                out.push(ch.to_ascii_uppercase());
                upper_next = false;
            } else {
                out.push(ch.to_ascii_lowercase());
            }
        } else {
            upper_next = true;
        }
    }
    if out.is_empty() {
        "Value".to_string()
    } else if is_rust_keyword(&out.to_ascii_lowercase()) {
        format!("{out}_")
    } else {
        out
    }
}

fn is_rust_keyword(s: &str) -> bool {
    matches!(
        s,
        "as" | "break"
            | "const"
            | "continue"
            | "crate"
            | "else"
            | "enum"
            | "extern"
            | "false"
            | "fn"
            | "for"
            | "if"
            | "impl"
            | "in"
            | "let"
            | "loop"
            | "match"
            | "mod"
            | "move"
            | "mut"
            | "pub"
            | "ref"
            | "return"
            | "self"
            | "Self"
            | "static"
            | "struct"
            | "super"
            | "trait"
            | "true"
            | "type"
            | "unsafe"
            | "use"
            | "where"
            | "while"
            | "async"
            | "await"
            | "dyn"
    )
}

fn indent_block(s: &str, spaces: usize) -> String {
    let pad = " ".repeat(spaces);
    s.lines()
        .map(|l| {
            if l.is_empty() {
                "\n".to_string()
            } else {
                format!("{pad}{l}\n")
            }
        })
        .collect()
}
